// Per-day meal system — one tiny call per day, reliably under 400 tokens output
// Calorie targets use Mifflin-St Jeor BMR × activity multiplier (P90X-style TDEE approach)
const MEAL_DAY_SYSTEM = `Nutritionist AI. Output JSON only, no markdown, no prose.
Plan:{PLAN_TYPE} Target:{CALORIES}kcal,{PROTEIN}p,{CARBS}c,{FAT}f Meals:{MEAL_COUNT}
Profile:{PROFILE}
ALLERGIES & RESTRICTIONS: {ALLERGIES}
SWAP SYSTEM — DO NOT EXCLUDE, SUBSTITUTE WITH LABEL:
User has these dietary restrictions. Keep the recipe but flag each affected ingredient with a swap label.
Format affected ingredients as: "original ingredient [SWAP: suggested swap — reason]"
Examples:
- Gluten-Free + pasta → "2 cups pasta [SWAP: chickpea pasta — gluten-free]"
- Dairy-Free + butter → "2 tbsp butter [SWAP: vegan butter — dairy-free]"
- Vegan + chicken → "6oz chicken breast [SWAP: firm tofu — plant-based protein]"
- Egg-Free + eggs → "2 eggs [SWAP: 2 flax eggs — egg-free binder]"
CRITICAL CLASSIFICATION RULES — these are the most common AI mistakes:
- EGGS ARE NOT DAIRY. Eggs do not need a swap for Dairy-Free. Only flag eggs for Egg-Free.
- ALMOND MILK, OAT MILK, COCONUT MILK, RICE MILK, SOY MILK are already dairy-free — NEVER flag them for Dairy-Free.
- ALMOND BUTTER, CASHEW BUTTER, SUNFLOWER SEED BUTTER are not dairy — NEVER flag for Dairy-Free.
- COCONUT OIL, COCONUT CREAM, COCONUT YOGURT are dairy-free — NEVER flag for Dairy-Free.
- ALMOND FLOUR, OAT FLOUR are not dairy — NEVER flag for Dairy-Free.
- NUTMEG is not a nut allergy trigger — NEVER flag for Nut-Free.
- EGGPLANT is not an egg — NEVER flag for Egg-Free.
- COCONUT is not a tree nut allergen in most classifications — use judgment for Nut-Free.
GENERAL RULES:
- KEEP the original recipe structure and meal name intact
- Flag ONLY ingredients that genuinely conflict with the restriction
- Non-conflicting ingredients stay exactly as-is
- The swap must be nutritionally similar (protein for protein, carb for carb)
- When the meal name contains a restricted ingredient, add "(adaptable)" after the name
Keep meal names under 4 words. Spread macros evenly across {MEAL_COUNT} meals.
For MASS BUILDER include 2 snack meals labeled type "Snack" in addition to Breakfast/Lunch/Dinner.
Return ONLY this exact JSON shape (no markdown):
{"day":"Mon","meals":[{"type":"Breakfast","name":"Egg Omelette","cal":350,"p":40,"c":15,"f":8,"ing":["4 egg whites","1 cup spinach"]},{"type":"Snack","name":"Protein Shake","cal":280,"p":35,"c":20,"f":5,"ing":["1 scoop whey","1 banana"]},{"type":"Lunch","name":"Chicken Bowl","cal":480,"p":50,"c":28,"f":11,"ing":["6oz chicken","1 cup rice","salsa"]},{"type":"Snack","name":"Cottage Cheese","cal":220,"p":28,"c":15,"f":4,"ing":["1 cup cottage cheese","berries"]},{"type":"Dinner","name":"Salmon Broccoli","cal":520,"p":46,"c":18,"f":16,"ing":["6oz salmon","2 cups broccoli"]},{"type":"Post-Workout","name":"Mass Shake","cal":400,"p":45,"c":50,"f":6,"ing":["2 scoops whey","1 cup oats","milk"]}],"tot":{"cal":2250,"p":244,"c":146,"f":50}}`;

// P90X-style Mifflin-St Jeor TDEE calculator
// Returns { calories, protein, carbs, fat, mealCount, tdee, bmr } based on user profile
const calcMacroTargets = (profile, planType) => {
  // Parse height → inches
  let heightIn = 67; // default 5'7"
  if (profile?.height) {
    const hStr = profile.height.toString().trim();
    const feetInch = hStr.match(/(\d+)['\s]+(\d+)/);
    const feetOnly = hStr.match(/^(\d+)'?$/);
    const cm = hStr.match(/^(\d{2,3})\s*cm/i);
    if (feetInch) heightIn = parseInt(feetInch[1]) * 12 + parseInt(feetInch[2]);
    else if (feetOnly) heightIn = parseInt(feetOnly[1]) * 12;
    else if (cm) heightIn = Math.round(parseInt(cm[1]) / 2.54);
  }
  const heightCm = heightIn * 2.54;

  // Parse weight → lbs then kg
  let weightLbs = 170;
  if (profile?.weight) {
    const w = parseFloat(profile.weight.toString().replace(/[^\d.]/g, ''));
    if (!isNaN(w) && w > 0) weightLbs = w;
  }
  const weightKg = weightLbs * 0.453592;

  // Parse age range → midpoint
  const ageMap = { "Under 20": 18, "20–29": 25, "30–39": 35, "40–49": 45, "50–59": 55, "60–69": 65, "70+": 72 };
  const age = ageMap[profile?.age] || 30;

  // Sex
  const isMale = (profile?.sex || "").toLowerCase().includes("male") && !(profile?.sex || "").toLowerCase().includes("female");

  // Mifflin-St Jeor BMR (kcal/day)
  // Male:   (10 × kg) + (6.25 × cm) - (5 × age) + 5
  // Female: (10 × kg) + (6.25 × cm) - (5 × age) - 161
  const bmr = isMale
    ? (10 * weightKg) + (6.25 * heightCm) - (5 * age) + 5
    : (10 * weightKg) + (6.25 * heightCm) - (5 * age) - 161;

  // Activity multiplier — P90X uses 1.2–1.9 scale
  const actMap = {
    "Sedentary": 1.2, "Sedentary (desk job, little exercise)": 1.2,
    "Lightly Active": 1.375, "Lightly Active (1-2x/week)": 1.375,
    "Moderately Active": 1.55, "Moderately Active (3-4x/week)": 1.55,
    "Very Active": 1.725, "Very Active (5+x/week)": 1.725,
    "Athlete": 1.9,
  };
  const actMultiplier = actMap[profile?.activityLevel] || 1.55;
  const tdee = Math.round(bmr * actMultiplier);

  // Plan-specific calorie adjustment & macros
  // P90X approach: Fat Shredder = deficit, Energy Booster = maintenance, Endurance = surplus
  // Mass Builder = aggressive surplus
  let cals, protein, carbs, fat, mealCount;
  const pt = (planType || "").toUpperCase();

  if (pt === "FAT SHRED") {
    // ~500 kcal deficit, high protein (1g/lb bodyweight), low carb
    cals    = Math.max(1400, Math.round(tdee - 500));
    protein = Math.round(weightLbs * 1.0);          // 1g/lb
    fat     = Math.round(cals * 0.20 / 9);
    carbs   = Math.round((cals - protein * 4 - fat * 9) / 4);
    mealCount = 5;
  } else if (pt === "BALANCE BOOSTER") {
    // Maintenance ±100, balanced 40/30/30
    cals    = tdee;
    protein = Math.round(weightLbs * 0.82);
    fat     = Math.round(cals * 0.30 / 9);
    carbs   = Math.round((cals - protein * 4 - fat * 9) / 4);
    mealCount = 5;
  } else if (pt === "ENDURANCE") {
    // ~300 surplus, carb-heavy 55/25/20
    cals    = Math.round(tdee + 300);
    protein = Math.round(weightLbs * 0.75);
    carbs   = Math.round(cals * 0.55 / 4);
    fat     = Math.round(cals * 0.20 / 9);
    mealCount = 5;
  } else if (pt === "MASS BUILDER") {
    // ~700 surplus, very high protein (1.2g/lb), high carb, 6 meals
    cals    = Math.round(tdee + 700);
    protein = Math.round(weightLbs * 1.2);           // 1.2g/lb for mass
    carbs   = Math.round(cals * 0.45 / 4);
    fat     = Math.round((cals - protein * 4 - carbs * 4) / 9);
    mealCount = 6;
  } else {
    cals = tdee; protein = Math.round(weightLbs * 0.82);
    fat = Math.round(cals * 0.30 / 9);
    carbs = Math.round((cals - protein * 4 - fat * 9) / 4);
    mealCount = 5;
  }

  // Floor guardrails
  protein = Math.max(protein, 100);
  carbs   = Math.max(carbs, 60);
  fat     = Math.max(fat, 30);

  return { calories: cals, protein, carbs, fat, mealCount, tdee, bmr: Math.round(bmr) };
};

