// Check URL params on load — Stripe redirects back with ?upgraded=true&tier=pro
// This grants Pro/Elite access after a successful payment
const checkStripeReturn = async () => {
  try {
    const params = new URLSearchParams(window.location.search);
    if (params.get('upgraded') === 'true') {
      const tier = params.get('tier') || 'pro';
      await window.storage.set('ailara:isPro', 'true');
      await window.storage.set('ailara:tier', tier);
      // Clean up URL so refreshing doesn't re-trigger
      window.history.replaceState({}, '', window.location.pathname);
    }
  } catch {}
};
checkStripeReturn();

// ── Storage shim — same API as Claude.ai window.storage ─────────────────────
// In Claude.ai artifact: window.storage is injected by the platform
// In web/PWA deployment: we use localStorage with the same API shape
if (typeof window !== "undefined" && !window.storage) {
  window.storage = {
    get: async (key) => {
      try {
        const val = localStorage.getItem(key);
        return val !== null ? { value: val } : null;
      } catch { return null; }
    },
    set: async (key, value) => {
      try { localStorage.setItem(key, String(value)); } catch {}
      return { key, value };
    },
    delete: async (key) => {
      try { localStorage.removeItem(key); } catch {}
      return { key, deleted: true };
    },
    list: async (prefix) => {
      try {
        const keys = Object.keys(localStorage)
          .filter(k => !prefix || k.startsWith(prefix));
        return { keys };
      } catch { return { keys: [] }; }
    },
    getAll: async () => {
      try {
        const entries = {};
        for (let i = 0; i < localStorage.length; i++) {
          const k = localStorage.key(i);
          if (k) entries[k] = localStorage.getItem(k);
        }
        return entries;
      } catch { return {}; }
    },
  };
}

